mapper.select:
SELECT b.booking_date AS usageDate, b.start_time AS startTime, b.end_time AS endTime, b.duration AS durationHours, b.experiment_project AS experimentProject, b.evaluation AS remark, CASE WHEN b.evaluation IS NOT NULL AND b.evaluation != '' THEN '正常' ELSE '正常' END AS usageResult, d.device_name AS deviceName, d.device_no AS deviceNo, COALESCE(NULLIF(TRIM(u.real_name), ''), u.username) AS userName, u.department FROM booking_order b INNER JOIN device_info d ON b.device_id = d.id AND d.deleted = 0 LEFT JOIN sys_user u ON b.user_id = u.id AND u.deleted = 0 WHERE b.status = 3 AND b.deleted = 0
AND d.device_name LIKE CONCAT('%', #{deviceName}, '%')
AND ( u.real_name LIKE CONCAT('%', #{userName}, '%') OR u.username LIKE CONCAT('%', #{userName}, '%') )
AND DATE(b.booking_date) >= #{startDate}
AND DATE(b.booking_date) <= #{endDate}
AND d.laboratory = #{laboratoryFilter}
ORDER BY b.booking_date DESC, b.start_time DESC
